<template>
    <div class="dashboard-view my-account outer-pad">
      <div class="dashboard-card__header dashboard-card__header--button">
        <dashboard-header :buttonText="this.$route.name === 'referencias-personales' ? 'Agregar referencia' : ''" routeLink="agregar-referencia" :title="getTitle(this.$route.name)" :previousTitle="this.$route.params.title"></dashboard-header>

      </div>
      <router-view v-slot="{ Component }">
        <transition name="fade" appear mode="out-in">
          <component :is="Component" />
        </transition>
      </router-view>
      <div class="component-spacer">
        <alert class="account__alert" typeOfAlert="accountDocChecked" v-if="isFilled"></alert>
      </div>
    </div>
</template>

<script>
import DashboardHeader from '../../components/dashboard/DashboardHeader'
import myAccountElements from '../../components/account/myAccountElements'
import Alert from '../../components/Alert'

export default {
  name: 'mi-cuenta',
  data () {
    return {
      isFilled: false
    }
  },
  components: {
    DashboardHeader,
    myAccountElements,
    Alert
  },
  methods: {
    getTitle (title) {
      const currentTitleSplit = title.split('-')
      const currentTitle = currentTitleSplit.reduce((acc, value) => acc + ' ' + value)
      return currentTitle
    }
  }
}
</script>
