<template>
  <div class="dashboard-view outer-pad">
    <div class="dashboard__header dashboard__header--button component-spacer">
      <dashboard-header :buttonText="this.$route.name === 'mis-prestamos' ? 'Solicitar préstamo' : ''" :routeLink="'solicitar-prestamo'" :title="getTitle(this.$route.name)" :previousTitle="this.$route.params.title"></dashboard-header>
    </div>
    <router-view v-slot="{ Component }">
      <transition name="fade" appear mode="out-in">
        <component :is="Component" />
      </transition>
    </router-view>
  </div>
</template>

<script>
import prestamosList from '../components/dashboard/prestamos/prestamosList'
import DashboardHeader from '../components/dashboard/DashboardHeader'

export default {
  name: 'prestamos',
  data () {
    return {
      prevRoute: '',
      nextRoute: ''
    }
  },
  methods: {
    getTitle (title) {
      const currentTitleSplit = title.split('-')
      const currentTitle = currentTitleSplit.reduce((acc, value) => acc + ' ' + value)
      return currentTitle
    }
  },
  components: {
    prestamosList,
    DashboardHeader
  },
  computed: {
    /* previousTitle () {

    } */
  },
  beforeRouteEnter (to, from, next) {
    next(vm => {
      vm.prevRoute = from
      vm.nextRoute = to
    })
  }
}
</script>
