<template>
  <transition name="fade" mode="out-in" appear>
    <div class="personal-data">
      <div class="form__card form__card--large outer-pad">
        <header class="form__card-header">
          <div class="h1">Datos personales</div>
        </header>
        <p class="form__card-description">Para que puedas acceder a los servicios y beneficios de Prospery, es necesario que sepamos más de ti.</p>
        <form @submit.prevent="this.$parent.stepCount()" action="submit" class="form__card-fields">
          <fieldset>
            <div class="silc-grid">
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="" class="label--input">Nombre Completo</label>
                <div class="tooltip">
                  <tool-tip-icon></tool-tip-icon>
                  <span class="tooltiptext">Tooltip text</span>
                </div>
                <input type="text" v-model="userData.personalData.fullName">
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="" class="label--input">Fecha de Nacimiento
                  <div class="tooltip">
                    <tool-tip-icon></tool-tip-icon>
                    <span class="tooltiptext">Tooltip text</span>
                  </div>
                </label>
                <input type="date" name="begin" v-model="userData.personalData.birthdate" placeholder="dd-mm-yyyy" min="1960-01-01" max="2002-1-1">
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="phone" class="label--input">Teléfono Móvil</label>
                <input type="tel" name="phone" id="phone" placeholder="3103923000" v-model="userData.personalData.cellphone">
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="" class="label--input">Teléfono Fijo</label>
                <input type="tel" name="phone" id="phone" placeholder="3103923000" v-model="userData.personalData.phone">
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="" class="label--input">Dirección</label>
                  <div class="tooltip">
                    <tool-tip-icon></tool-tip-icon>
                    <span class="tooltiptext">Tooltip text</span>
                  </div>
                <input type="address" v-model="this.userData.personalData.address">
              </div>
              <div class="silc-grid__col silc-grid__col--6-800">
                <label for="" class="label--input">Indicaciones</label>
                  <div class="tooltip">
                    <tool-tip-icon></tool-tip-icon>
                    <span class="tooltiptext">Tooltip text</span>
                  </div>
                <input type="text" v-model="this.userData.personalData.indications">
              </div>
            </div>
          </fieldset>
          <button class="button button--large"
            :class="{'button--disabled': !this.allDataFilled}"
            :disabled="!this.allDataFilled"
            >
              <span @click="submitForm">Continuar</span>
          </button>
        </form>
      </div>
      <div class="alert-wrapper">
        <alert v-if="!this.allDataFilled && this.submitted" typeOfAlert="allFieldsNeeded" class="personal-data__alert" ></alert>
      </div>
    </div>
  </transition>
