<script>
// @ is an alias to /src
import ToolTipIcon from '../../icons/textfields/tooltipActive'
import Alert from '../Alert.vue'

export default {
  name: 'PersonalData',
  data () {
    return {
      userData: {
        name: '',
        personalData: {
          fullName: '',
          birthdate: '',
          phone: '',
          cellphone: '',
          address: '',
          indications: ''
        }
      },
      submitted: false
    }
  },
  methods: {
    submitForm () {
      this.submitted = true
    }
  },
  components: {
    ToolTipIcon,
    Alert
  },
  computed: {
    allDataFilled () {
      return Object.values(this.userData.personalData).every(x => (x !== ''))
    }
  },
  mounted () {
  }
}
</script>
