                  <label for="" class="label label--input">¿Cuánto necesitas?</label>
                  <div class="ask-debt__input-wrapper">
                    <button class="button button--input ask-debt__form-button" @click="updateLoanQuantityController(-10000)">-</button>
                    <input class="ask-debt__form-input ask-debt__form-input--hidden-number" type="number" min="300000" max="1000000" name="" id="" v-model="loanQuantity" :class="{'ask-debt__form-input--filled': loanQuantity > 0}">
                    <p class="ask-debt__form-number">${{loanQuantityConverted}}</p>
                    <button class="button button--input ask-debt__form-button" @click="updateLoanQuantityController(10000)">+</button>
                  </div>
                </div>
                <div class="ask-debt__form-item">
                  <label for="" class="label label--input">¿En cuántas cuotas la puedes pagar?</label>
                  <div class="ask-debt__input-wrapper">
                    <button class="button button--input ask-debt__form-button" @click="updateLoanFee(-1)">-</button>
                    <input type="number" class="ask-debt__form-input" name="" id="" v-model="loanFee" :class="{'ask-debt__form-input--filled': loanFee > 0}">
                    <button class="button button--input ask-debt__form-button" @click="updateLoanFee(1)">+</button>
                  </div>
                </div>
                <div class="ask-debt__form-item">
                  <label for="" class="label label--input">¿Para cuándo lo necesitas?</label>
                  <div class="ask-debt__input-wrapper">
                    <input type="text"
                           class="ask-debt__datepicker ask-debt__form-input ask-debt__form-input--date"
                           placeholder="dd/mm/yyyy"
                           :value="selectedDate"
                           @click="showDatepicker = true">
                  </div>
                </div>
              </div>
            </div>
          </section>
        </div>
      </div>
      <div class="silc-grid__col silc-grid__col--6-900">
        <div class="dashboard-card outer-pad outer-pad--small">
          <header class="dashboard-card__header">
            <div class="h2 dashboard-card__header-title">Resumen de tu solicitud</div>
          </header>
          <section class="dashboard-card__content">
            <div class="dashboard-card__content-wrapper">

              <ul class="dashboard-card__list-wrapper">
                <li class="dashboard-card__list-item">
                  <div class="inline-icon__wrapper">
                    <interest-icon class="medium-icon"></interest-icon>
                    <p class="paragraph--dark">Interés: 25% E.A.</p>
                    <alert-icon class="small-icon icon-gray--disabled"></alert-icon>
                  </div>
