                    <p class="paragraph--dark">Subtotal</p>
                    <alert-icon class="small-icon icon-gray--disabled"></alert-icon>
                  </div>
                  <div class="dashboard-card__number dashboard-card__number--small">$55.000</div>
                </li>
                <li class="dashboard-card__list-item">
                  <div class="inline-icon__wrapper">
                    <interest-icon class="medium-icon icon-gray"></interest-icon>
                    <p class="paragraph--dark">IVA</p>
                    <alert-icon class="small-icon icon-gray--disabled"></alert-icon>
                  </div>
                  <div class="dashboard-card__number dashboard-card__number--small">$55.000</div>
