</template>

<script>
import interestIcon from '../icons/dashboard/interestIcon'
import alertIcon from '../icons/dashboard/alertIcon'
import additionalServicesIcon from '../icons/dashboard/additionalServicesIcon'
import moneyIcon from '../icons/dashboard/moneyIcon'
import Datepicker from '../components/dashboard/prestamos/Datepicker.vue'

export default {
  name: 'solicitar-prestamo',
  data () {
    return {
      loanQuantity: 0,
      loanFee: 0,
      showDatepicker: false,
      selectedDate: null
    }
  },
  methods: {
    updateLoanQuantity (number) {
      this.loanQuantity = Number(number)
      this.updateLoanQuantityController(0)
    },

    updateLoanQuantityController (number) {
      this.loanQuantity += number
      this.loanQuantityConverted = this.loanQuantity.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.')
    },
    updateLoanFee (factor) {
      this.loanFee += factor
    }
  },
  components: {
    interestIcon,
    alertIcon,
    additionalServicesIcon,
    moneyIcon,
    Datepicker
  },
  computed: {
    loanQuantityConverted () {
      return this.loanQuantity.toString().replace(/\B(?=(\d{3})+(?!\d))/g, '.')
    }
  }
}
</script>
